it("should return premium 65 G for 3 runes — 60 G base (block of 3 alike) + 5 G fee", () => {
  const input = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote" as const,
        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
      },
    ],
  };
  const result = claimOffice(input);
  expect(result).toEqual({ results: [{ premium: 65 }] });
});

